vulnerable.snippet:
import amqp from "amqplib";

export function connectBroker(url: string) {
  // VULNERABLE: rejectUnauthorized: false — the RabbitMQ broker certificate is not validated.
  return amqp.connect(url, { rejectUnauthorized: false });
}

fixed.snippet:
import amqp from "amqplib";

export function connectBroker(url: string, ca: string) {
  // FIXED: certificate validation enforced; trust the broker CA explicitly.
  return amqp.connect(url, { rejectUnauthorized: true, ca: [ca] });
}

