import { ApolloServer } from "@apollo/server";

export function makeApollo(typeDefs: string, resolvers: object) {
  // VULNERABLE: csrfPrevention: false lets simple cross-site requests drive authenticated mutations.
  return new ApolloServer({ typeDefs, resolvers, csrfPrevention: false });
}

fixed.snippet:
import { ApolloServer } from "@apollo/server";

export function makeApollo(typeDefs: string, resolvers: object) {
  // FIXED: CSRF prevention stays enabled (the Apollo Server 4 default).
  return new ApolloServer({ typeDefs, resolvers, csrfPrevention: true });
}

vulnerable.snippet:
import AWS from "aws-sdk";

export function uploadUserFile(s3: AWS.S3, key: string, body: Buffer) {
  // VULNERABLE: public-read makes every uploaded object readable by anyone on the internet.
  return s3.putObject({ Bucket: "user-uploads", Key: key, Body: body, ACL: "public-read" }).promise();
}

fixed.snippet:
import AWS from "aws-sdk";

export function uploadUserFile(s3: AWS.S3, key: string, body: Buffer) {
  // FIXED: objects are private; serve them via pre-signed URLs when needed.
  return s3.putObject({ Bucket: "user-uploads", Key: key, Body: body, ACL: "private" }).promise();
}
